            let current = nums[i];
            let target = sorted[i];

            // Find a number in nums that can be swapped with current to reach target
            let found = false;
            for (let j = 0; j < n; j++) {
                if (visited[j]) continue;
                if ((current & nums[j]) === k && nums[j] === target) {
